using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public Dictionary<string, PerClassMetrics> PerClassMetrics { get; set; } = new();
}

public class PerClassMetrics
{
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _classLabels;

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void Train()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract the ordered class labels from the Label key column
        var labelColumn = _model.GetOutputSchema(dataView.Schema)["Label"];
        var labelKeyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        var labelMetadata = labelColumn.Annotations;
        var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
        labelMetadata.GetValue("KeyValues", ref slotNames);
        _classLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
    }

    public EvaluationResponse Evaluate()
    {
        if (_model is null)
            throw new InvalidOperationException("Model must be trained before evaluation.");

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var response = new EvaluationResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction
        };

        // Per-class precision, recall, and F1 from the confusion matrix
        var confusionMatrix = metrics.ConfusionMatrix;
        var classNames = confusionMatrix.PerClassPrecision
            .Select((_, i) => _classLabels is not null && i < _classLabels.Length
                ? _classLabels[i]
                : $"Class{i}")
            .ToArray();

        for (int i = 0; i < classNames.Length; i++)
        {
            var precision = confusionMatrix.PerClassPrecision[i];
            var recall = confusionMatrix.PerClassRecall[i];
            var f1 = precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;

            response.PerClassMetrics[classNames[i]] = new PerClassMetrics
            {
                Precision = Math.Round(precision, 4),
                Recall = Math.Round(recall, 4),
                F1Score = Math.Round(f1, 4)
            };
        }

        return response;
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null || _classLabels is null)
            throw new InvalidOperationException("Model must be trained before prediction.");

        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classLabels[i]] = (float)Math.Round(prediction.Score[i], 4);
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketClassifierController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("train")]
    public IActionResult Train()
    {
        _classifier.Train();
        return Ok(new { message = "Model trained successfully." });
    }

    [HttpGet("evaluate")]
    public IActionResult Evaluate()
    {
        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model not trained. POST /api/ticketclassifier/train first." });

        var metrics = _classifier.Evaluate();
        return Ok(metrics);
    }

    [HttpPost("predict")]
    public IActionResult Predict([FromBody] TicketRequest request)
    {
        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model not trained. POST /api/ticketclassifier/train first." });

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        var result = _classifier.Predict(request);
        return Ok(result);
    }
}

